+                let recipient = register_agent(&cx, &pool, project_id, "RedPeak").await;
+                let hidden = register_agent(&cx, &pool, project_id, "GreyOwl").await;
+                let thread_id = format!("thread-bcc-{}", unique_suffix());
+                let message = create_message_with_bcc(
