+                    "Hidden Subject",
+                    "Hidden body.",
+                    &thread_id,
+                    true,
+                )
+                .await;
+
+                let ctx = McpContext::new(cx.clone(), 1);
+                let project_ref = project.human_key.clone();
+
+                let message_value = parse_json(
